mapper.select:
SELECT ITEMNAME
FROM T_MI_ITEM
WHERE ITEMCODE = #{itemcode}

SELECT COUNT(*)
FROM T_WMS_WORKREALSTOCK
WHERE USEYN ='Y'
AND ITEMCODE = #{itemcode}
AND QTY = #{qty}
AND SDATE = #{date}
AND STORAGE = #{workshop}

mapper.update:
UPDATE T_WMS_WORKREALSTOCK
   SET USEYN = 'N'
     , YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
     , MEMO_D = 'FIX QTY'
 WHERE SDATE = #{date}
   AND ITEMCODE = #{itemcode}
   AND STORAGE = #{workshop}
   AND USEYN = 'Y'

mapper.select:
SELECT * FROM ( SELECT rownum rn, t.* FROM ( SELECT a.barcode, a.indate, a.factory, a.storage, c.subname_ch as car, a.itemcode, b.itemname, SUM(a.qty) as qty, nvl(a.oldlocation,' ') as oldlocation, a.source, a.rack FROM t_wms_worklocation a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE (a.rack IS NULL or a.rack = '-' OR a.module IS NULL or a.module = '-' OR a.levelcode IS NULL OR a.levelcode = '-' OR a.position IS NULL OR a.position = '-') AND a.useyn = 'Y'
GROUP BY a.barcode, a.indate, a.factory, a.storage, c.subname_ch, a.itemcode, b.itemname, a.source, a.oldlocation, a.rack ORDER BY a.indate desc, a.itemcode
) t WHERE rownum <= #{offset} + #{itemsPerPage} ) WHERE rn > #{offset}

mapper.delete:
delete from t_wms_realstocknotscan
where factory = #{factory}
and storage =#{storage}
and sdate = #{date}

mapper.select:
    	SELECT 
			V.*,
		    SUM(V.TOTAL_QTY) OVER () AS TOTALQTY
		FROM (
		    SELECT
				a.ITEMCODE,
				b.ITEMNAME,
				/* 1. INVENTORY */
				SUM(CASE WHEN KIND = 'INVENTORY' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS INVENTORY_QTY,
				/* 2. INCOMING EXCEPTION */
				SUM(CASE WHEN KIND = 'INCOMING EXCEPTION' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS INCOMING_EXCEPTION_QTY,
				/* 3. WIP INPUT */
				SUM(CASE WHEN KIND = 'WIP INPUT' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS WIP_INPUT_QTY,
				/* 4. WIP RETURN */
				SUM(CASE WHEN KIND = 'WIP RETURN' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS WIP_RETURN_QTY,
				/* 5. LOAD EXCEPTION */
				SUM(CASE WHEN KIND = 'LOAD EXCEPTION' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS LOAD_EXCEPTION_QTY,
				/* 6. INCOMING EXCEPTION */
				SUM(CASE WHEN KIND = 'TOREDCAGE' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS TOREDCAGE_QTY,
				/* 7. PRODUCTION */
				SUM(CASE WHEN KIND = 'PRODUCTION' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS PRODUCTION_QTY,
				/* 8. PRODUCTIONMOVE */
				SUM(CASE WHEN KIND = 'PRODUCTIONMOVE' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS PRODUCTIONMOVE_QTY,
				/* 9. PRODUCTIONMOVE */
				SUM(CASE WHEN KIND = 'PRODUCTION USED' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS PRODUCTIONUSED_QTY,
				/* 10. DISASSEMBLY */
				SUM(CASE WHEN KIND = 'DISASSEMBLY' THEN PLUSQTY - MINUSQTY ELSE 0 END) AS DISASSEMBLY_QTY,
				/* ▶ TOTAL (전부 합계) */
				SUM(PLUSQTY - MINUSQTY) AS TOTAL_QTY
			FROM V_WORKSTOCK a
		    LEFT JOIN t_mi_item B ON A.ITEMCODE = B.ITEMCODE
		    WHERE 1 = 1 

		    GROUP BY A.ITEMCODE, B.ITEMNAME
		) V
		ORDER BY V.ITEMCODE
